9584 void llvm::findValuesAffectedByCondition(
9585     Value *Cond, bool IsAssume, function_ref<void(Value *)> InsertAffected) {
9586   auto AddAffected = [&InsertAffected](Value *V) {
9587     addValueAffectedByCondition(V, InsertAffected);
9588   };
9589 
9590   auto AddCmpOperands = [&AddAffected, IsAssume](Value *LHS, Value *RHS) {
9591     if (IsAssume) {
9592       AddAffected(LHS);
9593       AddAffected(RHS);
9594     } else if (match(RHS, m_Constant()))
9595       AddAffected(LHS);
9596   };
9597 
9598   SmallVector<Value *, 8> Worklist;
9599   SmallPtrSet<Value *, 8> Visited;
9600   Worklist.push_back(Cond);
9601   while (!Worklist.empty()) {
9602     Value *V = Worklist.pop_back_val();
9603     if (!Visited.insert(V).second)
9604       continue;
9605 
9606     CmpInst::Predicate Pred;
9607     Value *A, *B, *X;
9608 
9609     if (IsAssume) {
9610       AddAffected(V);
9611       if (match(V, m_Not(m_Value(X))))
9612         AddAffected(X);
9613     }
9614 
9615     if (match(V, m_LogicalOp(m_Value(A), m_Value(B)))) {
9616       // assume(A && B) is split to -> assume(A); assume(B);
9617       // assume(!(A || B)) is split to -> assume(!A); assume(!B);
9618       // Finally, assume(A || B) / assume(!(A && B)) generally don't provide
9619       // enough information to be worth handling (intersection of information as
9620       // opposed to union).
9621       if (!IsAssume) {
9622         Worklist.push_back(A);
9623         Worklist.push_back(B);
9624       }
9625     } else if (match(V, m_ICmp(Pred, m_Value(A), m_Value(B)))) {
9626       AddCmpOperands(A, B);
9627 
9628       if (ICmpInst::isEquality(Pred)) {
9629         if (match(B, m_ConstantInt())) {
9630           Value *Y;
9631           // (X & C) or (X | C) or (X ^ C).
9632           // (X << C) or (X >>_s C) or (X >>_u C).
9633           if (match(A, m_BitwiseLogic(m_Value(X), m_ConstantInt())) ||
9634               match(A, m_Shift(m_Value(X), m_ConstantInt())))
9635             AddAffected(X);
9636           else if (match(A, m_And(m_Value(X), m_Value(Y))) ||
9637                    match(A, m_Or(m_Value(X), m_Value(Y)))) {
9638             AddAffected(X);
9639             AddAffected(Y);
9640           }
9641         }
9642       } else {
9643         if (match(B, m_ConstantInt())) {
